import { Component, Input, OnInit } from '@angular/core';
import { ITableColumn } from '../../../../models/table.interface';
import { CommonModule } from '@angular/common';
import { TableModule } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { TieredMenuModule } from 'primeng/tieredmenu';
import { TagModule } from 'primeng/tag';
import { TagSeverity } from '../../../../constant/tag-status.data';

@Component({
  selector: 'tr[pla-table-body]',
  imports: [
    TableModule,
    CommonModule,
    ButtonModule,
    TieredMenuModule,
    TagModule,
  ],
  templateUrl: './pla-table-body.component.html',
  styleUrl: './pla-table-body.component.scss',
})
export class PlaTableBodyComponent<T = unknown> implements OnInit {
  @Input({ required: true }) tableColumns: ITableColumn<T>[] = [];
  @Input({ required: true }) rowData: any;
  @Input({ required: true }) rowIndex: number = 0;

  ngOnInit(): void {}

  getSeverity(status: TagSeverity) {
    switch (status) {
      case 'secondary':
        return 'secondary';
      case 'warn':
        return 'warn';
      case 'success':
        return 'success';
      case 'danger':
        return 'danger';
      case 'info':
        return 'info';
      case 'contrast':
        return 'contrast';
      default:
        return 'secondary';
    }
  }
}
