import { Injectable } from '@angular/core';
import { GroupMenu, IMenu } from '../models/user-profile.interface';

@Injectable({
  providedIn: 'root',
})
export class MenuService {
  async getGroupMenu(
    targetPath: string,
    storage: string,
  ): Promise<IMenu | null> {
    const prefixPath = targetPath.split('gio');
    const currentPath = prefixPath[0].split('/');
    const currentUrl = currentPath[1].toLowerCase();

    const dataState = await this.fetchData(storage);
    const groupMenus = dataState.user?.groupMenus;
    if (!groupMenus) return null;

    const findMenuPath = (
      menus: GroupMenu[],
      url: string,
      path: GroupMenu[] = [],
    ): GroupMenu[] | null => {
      for (const menu of menus) {
        const parsedUrl = (menu.menuURL || '')
          .replace(/^\/+/, '')
          .replace(/\s+/g, '-')
          .toLowerCase();

        const newPath = [...path, menu];

        if (parsedUrl === url) {
          return newPath;
        }

        if (menu.groupMenus?.length) {
          const found = findMenuPath(menu.groupMenus, url, newPath);
          if (found) return found;
        }
      }
      return null;
    };

    const fullPath = findMenuPath(groupMenus, currentUrl);
    if (!fullPath) return null;

    const targetMenu = fullPath[fullPath.length - 1];
    return { targetMenu, path: fullPath };
  }

  async getMenus(storage: string): Promise<GroupMenu[]> {
    const dataState = await this.fetchData(storage);
    const flatten = (menus: GroupMenu[] = []): GroupMenu[] =>
      menus.reduce((acc, item) => {
        if (item.menuURL) acc.push(item);
        if (item.groupMenus) acc.push(...flatten(item.groupMenus));
        return acc;
      }, [] as GroupMenu[]);

    return flatten(dataState.user?.groupMenus);
  }

  fetchData(storage: string) {
    try {
      const sessionData = localStorage.getItem(storage);
      const data = JSON.parse(sessionData || '{}');
      return data;
    } catch (error) {
      return {};
    }
  }
}
