import { Component, Input, OnChanges, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';

import { TableModule } from 'primeng/table';
import { InputTextModule } from 'primeng/inputtext';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';

import {
  IAppliedFilters,
  IOperatorOptions,
  ITableColumn,
} from '../../../../../../models/table.interface';
import { debounceTime, Subject } from 'rxjs';

@Component({
  selector: 'pla-table-filter-input-text',
  imports: [
    CommonModule,
    TableModule,
    IconFieldModule,
    InputIconModule,
    IconFieldModule,
    InputTextModule,
  ],
  templateUrl: './pla-table-filter-input-text.component.html',
  styleUrl: './pla-table-filter-input-text.component.scss',
})
export class PlaTableFilterInputTextComponent<T = ITableColumn<any>>
  implements OnInit, OnChanges
{
  @Input({ required: true }) column: ITableColumn<T> = {
    field: '',
    title: '',
    columnType: 'text',
  };
  @Input({ required: true }) appliedFilters: IAppliedFilters = {};
  @Input({ required: true }) operatorOptions: IOperatorOptions[] = [];

  private readonly filterTextSubject = new Subject<{
    field: string;
    value: string;
    callback: (value: unknown) => void;
  }>();

  private skipNextInput: boolean = false;

  ngOnInit(): void {
    this.initTextSearch();
  }

  ngOnChanges(): void {}

  initTextSearch() {
    this.filterTextSubject
      .pipe(debounceTime(1500))
      .subscribe(({ value, callback }) => {
        if (!this.skipNextInput) {
          callback(value);
        }
      });
  }

  clearFilter(
    input: HTMLInputElement,
    field: string,
    callback: (value: unknown) => void,
  ) {
    input.value = '';
    callback(null);
  }

  onTextFilterChange(
    event: Event,
    field: string,
    callback: (value: unknown) => void,
  ): void {
    const input = event.target as HTMLInputElement;
    const value = input.value;

    this.skipNextInput = false;
    this.filterTextSubject.next({ field, value, callback });
  }

  onTextFilterEnter(event: Event, callback: (value: unknown) => void): void {
    const input = event.target as HTMLInputElement;
    this.skipNextInput = true;
    callback(input.value);
  }
}
