import {
  Directive,
  Input,
  TemplateRef,
  ViewContainerRef,
  OnInit,
  inject,
} from '@angular/core';
import { PermissionService } from '../services/permission.service';

@Directive({
  selector: '[appHasMenuUAM]',
})
export class HasMenuUAMDirective implements OnInit {
  @Input('appHasMenuUAM') menuUrl!: string;
  @Input('appHasMenuUAMStorage') storage!: string;

  private templateRef = inject(TemplateRef<unknown>);
  private viewContainer = inject(ViewContainerRef);
  private permissionService = inject(PermissionService);

  async ngOnInit(): Promise<void> {
    if (this.menuUrl) {
      if (await this.permissionService.hasMenuUAM(this.menuUrl, this.storage)) {
        this.viewContainer.createEmbeddedView(this.templateRef);
      } else {
        this.viewContainer.clear();
      }
    } else {
      this.viewContainer.createEmbeddedView(this.templateRef);
    }
  }
}
