import { CommonModule } from '@angular/common';
import { Component, EventEmitter, Input, Output } from '@angular/core';
import {
  FormControl,
  FormGroup,
  FormsModule,
  ReactiveFormsModule,
} from '@angular/forms';

import { FloatLabelModule } from 'primeng/floatlabel';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIcon } from 'primeng/inputicon';
import { InputTextModule } from 'primeng/inputtext';
import { KeyFilterModule } from 'primeng/keyfilter';

import { OverlayTextDirective } from '../../directives/overlay-text.directive';
import { CharCountDirective } from '../../directives/char-count.directive';
import { IFormControlDynamic } from '../pla-dynamic-form/form.interface';
import { classValidate, isRequired } from '../../utils/pla-utils';

@Component({
  selector: 'pla-form-input-text',
  imports: [
    FormsModule,
    CommonModule,
    ReactiveFormsModule,
    FloatLabelModule,
    FloatLabelModule,
    InputIcon,
    IconFieldModule,
    InputTextModule,
    KeyFilterModule,
    OverlayTextDirective,
    CharCountDirective,
  ],
  templateUrl: './pla-form-input-text.component.html',
  styleUrl: './pla-form-input-text.component.scss',
})
export class PlaFormInputTextComponent {
  @Input() control!: IFormControlDynamic;
  @Input() listFormGroup!: FormGroup;
  @Input() formControl!: FormControl;
  @Input() submitted = false;
  @Input() index: number | null = null; // For Input form array only

  @Output() valueChange = new EventEmitter<any>();

  isRequired: Function = isRequired;
  classValidate: Function = classValidate;

  ngOnInit() {}

  onValueChange(newValue: any) {
    this.control.value = newValue;
    this.valueChange.emit(newValue);
  }

  onHandle(event: any): void {
    console.log('testValue1.0', event);
  }
}
