import { Component, Input, OnInit } from '@angular/core';

import { CommonModule } from '@angular/common';
import { TableModule } from 'primeng/table';

import {
  ITableColumn,
  IAppliedFilters,
  IOperatorOptions,
} from '../../../../models/table.interface';
import { PlaTableFilterInputTextComponent } from './components/pla-table-filter-input-text/pla-table-filter-input-text.component';
import { PlaTableFilterMultiSelectComponent } from './components/pla-table-filter-multi-select/pla-table-filter-multi-select.component';
import { PlaTableFilterDateComponent } from './components/pla-table-filter-date/pla-table-filter-date.component';
import { FilterMatchMode } from 'primeng/api';

@Component({
  selector: 'tr[pla-table-filter]',
  imports: [
    TableModule,
    CommonModule,
    PlaTableFilterInputTextComponent,
    PlaTableFilterMultiSelectComponent,
    PlaTableFilterDateComponent,
  ],
  templateUrl: './pla-table-filter.component.html',
  styleUrl: './pla-table-filter.component.scss',
})
export class PlaTableFilterComponent<T = unknown> implements OnInit {
  @Input({ required: true }) tableColumns: ITableColumn<T>[] = [];
  @Input({ required: true }) appliedFilters: IAppliedFilters = {};

  public readonly operatorOptions: IOperatorOptions[] = [
    { label: 'Starts With', value: FilterMatchMode.STARTS_WITH },
    { label: 'Contains', value: FilterMatchMode.CONTAINS },
    { label: 'Ends With', value: FilterMatchMode.ENDS_WITH },
    { label: 'Equals', value: FilterMatchMode.EQUALS },
    { label: 'Not Equals', value: FilterMatchMode.NOT_EQUALS },
  ];

  ngOnInit(): void {}
}
