import { Component, Input, OnInit } from '@angular/core';

import {
  IAppliedFilters,
  ITableColumn,
} from '../../../../../../models/table.interface';
import { CommonModule } from '@angular/common';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { TableModule } from 'primeng/table';
import { DatePickerModule } from 'primeng/datepicker';
import { FormsModule } from '@angular/forms'; // 1. Import this

@Component({
  selector: 'pla-table-filter-date',
  imports: [
    FormsModule,
    CommonModule,
    TableModule,
    IconFieldModule,
    InputIconModule,
    IconFieldModule,
    DatePickerModule,
  ],
  templateUrl: './pla-table-filter-date.component.html',
  styleUrl: './pla-table-filter-date.component.scss',
})
export class PlaTableFilterDateComponent<
  T = ITableColumn<any>,
> implements OnInit {
  @Input({ required: true }) appliedFilters: IAppliedFilters = {};
  @Input() column: ITableColumn<T> = {
    field: '',
    title: '',
    columnType: 'date',
  };

  ngOnInit(): void {}

  onDateChange(event: any, filterCallback: Function) {
    if (Array.isArray(event) && event[0] && event[1]) {
      const startDate = new Date(event[0]);
      const endDate = new Date(event[1]);
      // Remark: Need to set Time of actual data start date to midnight. Set Start to 00:00:00.000
      startDate.setHours(0, 0, 0, 0);
      // Remark: Need to set Time of actual data end date before midnight. Set End to 23:59:59.999
      // so it includes the whole last day
      endDate.setHours(23, 59, 59, 999);

      filterCallback([startDate, endDate]);
    } else {
      filterCallback(event);
    }
  }
}
