import { Component, Input, OnInit } from '@angular/core';
import {
  IAppliedFilters,
  IOperatorOptions,
  ITableColumn,
} from '../../../../../../models/table.interface';
import { CommonModule } from '@angular/common';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { InputTextModule } from 'primeng/inputtext';
import { TableModule } from 'primeng/table';
import { MultiSelectModule } from 'primeng/multiselect';
import { FormsModule } from '@angular/forms'; // 1. Import this
@Component({
  selector: 'pla-table-filter-multi-select',
  imports: [
    CommonModule,
    TableModule,
    IconFieldModule,
    InputIconModule,
    IconFieldModule,
    InputTextModule,
    MultiSelectModule,
    FormsModule,
  ],
  templateUrl: './pla-table-filter-multi-select.component.html',
  styleUrl: './pla-table-filter-multi-select.component.scss',
})
export class PlaTableFilterMultiSelectComponent<
  T = ITableColumn<any>,
> implements OnInit {
  @Input() column: ITableColumn<T> = {
    field: '',
    title: '',
    columnType: 'tag',
  };
  @Input({ required: true }) appliedFilters: IAppliedFilters = {};
  @Input({ required: true }) operatorOptions: IOperatorOptions[] = [];

  ngOnInit(): void {}

  onSelectFilter(
    value: string,

    callback: (value: unknown) => void,
  ) {
    callback(value);
  }
}
