import {
  Component,
  EventEmitter,
  Input,
  OnChanges,
  OnInit,
  Output,
  ViewChild,
} from '@angular/core';
import {
  Table,
  TableFilterEvent,
  TableLazyLoadEvent,
  TableModule,
} from 'primeng/table';
import { FilterMatchMode, FilterMetadata, SortEvent } from 'primeng/api';
import { CommonModule } from '@angular/common';

import {
  IAppliedFilters,
  IFilterColumn,
  IPaginatorProperties,
  ITableColumn,
  ITableConfig,
  ITableLazyLoad,
  ITablePaginator,
  ITableSearchPayload,
  OPERATOR,
} from '../../models/table.interface';

import { PlaTableHeaderComponent } from './components/pla-table-header/pla-table-header.component';
import { PlaTableBodyComponent } from './components/pla-table-body/pla-table-body.component';
import { PlaTableFilterComponent } from './components/pla-table-filter/pla-table-filter.component';

const DEFAULT_TABLE_LAZY_LOAD_CONFIG: ITableLazyLoad = {
  islazyLoad: false,
  totalRecord: 0,
};
const DEFAULT_FIRST_PAGE = 0;
const DEFAULT_ROW_PER_PAGE = 10;
const DEFAULT_TABLE_PAGINATOR_CONFIG: ITablePaginator = {
  isShowPagination: true,
  paginatorProperties: {
    rowsPerPageOptions: [10, 25, 50],
    showCurrentPageReport: true,
    currentPageReportTemplate:
      'Showing {first} to {last} of {totalRecords} entries',
    paginatorDropdownAppendTo: 'body',
  },
};

@Component({
  selector: 'pla-table',
  standalone: true,
  imports: [
    TableModule,
    CommonModule,
    PlaTableHeaderComponent,
    PlaTableFilterComponent,
    PlaTableBodyComponent,
  ],
  templateUrl: './pla-table.component.html',
  styleUrl: './pla-table.component.scss',
})
export class PlaTableComponent<T = unknown> implements OnInit, OnChanges {
  @ViewChild('dt') table!: Table;

  @Input({ required: true }) tableLoading: boolean = false;
  @Input({ required: true }) tableData: T[] = [];
  @Input({ required: true }) tableColumns: ITableColumn<T>[] = [];
  @Input({ required: true }) tableConfig: ITableConfig = {
    first: DEFAULT_FIRST_PAGE,
    rows: DEFAULT_ROW_PER_PAGE,
    tableLazyLoadConfig: DEFAULT_TABLE_LAZY_LOAD_CONFIG,
    tablePaginatorConfig: DEFAULT_TABLE_PAGINATOR_CONFIG,
  };

  // Remark: Get event that emit by p-table of primeNG type of the event is FilterMetadata.
  @Input() appliedFilters: IAppliedFilters = {};
  @Input({ required: true }) applicationStorageName: string = '';
  @Input({ required: true }) tableName: string = '';

  @Output() onChangeTableFiltersEmit = new EventEmitter<any>();

  rows = DEFAULT_ROW_PER_PAGE;
  public skeletonTable: number[] = Array.from({
    length: DEFAULT_ROW_PER_PAGE,
  }).map((_, i) => i);

  ngOnInit(): void {
    this.onGetFilterFromLocalStorage();
  }

  ngOnChanges(): void {
    // this.onGetFilterFromLocalStorage();
  }

  get paginatorConfig(): IPaginatorProperties {
    return this.tableConfig.tablePaginatorConfig.isShowPagination
      ? this.tableConfig.tablePaginatorConfig.paginatorProperties
      : {
          rowsPerPageOptions: [],
          showCurrentPageReport: false,
          paginatorDropdownAppendTo: 'body',
          currentPageReportTemplate: '',
        };
  }

  customSort(event: SortEvent) {
    event.data?.sort((data1, data2) => {
      const field = event.field!;
      let value1 = data1[field];
      let value2 = data2[field];

      // Handle tag columns (objects with 'value' property)
      if (typeof value1 === 'object' && value1?.value) {
        value1 = value1.value;
      }
      if (typeof value2 === 'object' && value2?.value) {
        value2 = value2.value;
      }

      let result = 0;

      if (value1 == null && value2 != null) {
        result = -1;
      } else if (value1 != null && value2 == null) {
        result = 1;
      } else if (value1 == null && value2 == null) {
        result = 0;
      } else if (typeof value1 === 'string' && typeof value2 === 'string') {
        result = value1.localeCompare(value2);
      } else {
        result = value1 < value2 ? -1 : value1 > value2 ? 1 : 0;
      }

      return event.order! * result;
    });
  }

  onChangeFilter(event: TableFilterEvent) {
    // 1. Deep clone the filters so we don't mutate the live UI state
    const filtersToSave = JSON.parse(
      JSON.stringify(event.filters, (key, value) => {
        // Check if the value is a date string or object
        if (this.isDate(value)) {
          const date = new Date(value);
          // Offset the date so that toISOString() returns your local time as "Z"
          const offset = date.getTimezoneOffset() * 60000;
          return (
            new Date(date.getTime() - offset).toISOString().split('T')[0] +
            'T00:00:00.000Z'
          );
        }
        return value;
      }),
    );

    const currentAppStorageData =
      localStorage.getItem(this.applicationStorageName) || '{}';
    const dataState = JSON.parse(currentAppStorageData);

    this.appliedFilters = (event.filters ?? {}) as Record<
      string,
      FilterMetadata
    >;

    Object.assign(dataState, {
      filter: {
        ...dataState.filter,
        [this.tableName]: filtersToSave, // Save the adjusted filters
      },
    });

    localStorage.setItem(
      this.applicationStorageName,
      JSON.stringify(dataState),
    );
  }

  // Helper to detect dates
  private isDate(value: any): boolean {
    return (
      value instanceof Date ||
      (typeof value === 'string' &&
        !isNaN(Date.parse(value)) &&
        value.length > 15)
    );
  }

  onGetFilterFromLocalStorage(): void {
    const currentAppStorageData =
      localStorage.getItem(this.applicationStorageName) || '{}';
    const currentFilter = JSON.parse(currentAppStorageData).filter?.[
      this.tableName
    ] as IAppliedFilters | undefined;

    if (currentFilter) {
      this.normalizeDateFilters(currentFilter);
      this.appliedFilters = currentFilter;
      // this.onSetFilterToLocalStorage(currentFilter);
    } else {
      const defaultFilters = this.buildDefaultFilters();
      this.appliedFilters = defaultFilters;
      // this.table?._filter();
    }
  }

  private normalizeDateFilters(filters: IAppliedFilters): void {
    // Get all keys from the filters object
    Object.keys(filters).forEach((key) => {
      // Remark: Use match mode as between for date column.
      if (key.toLowerCase().includes('date')) {
        const field = filters[key];

        // Ensure the field exists and has a truthy value before converting
        if (field?.value) {
          field.value = Array.isArray(field.value)
            ? field.value.map((date: any) => (date ? new Date(date) : null))
            : new Date(field.value);
        }
      }
    });
  }

  private buildDefaultFilters(): IAppliedFilters {
    // Remark: Use match mode as between for date column.
    return this.tableColumns
      .filter((col) => col.field)
      .reduce((acc, col) => {
        acc[col.field] = {
          value: null,
          matchMode: this.initFilterMatchMode(col?.filterType),
        };
        return acc;
      }, {} as IAppliedFilters);
  }

  private initFilterMatchMode(filterType: string | undefined): string {
    if (filterType === 'date') {
      return FilterMatchMode.BETWEEN;
    } else if (filterType === 'multi-select') {
      return FilterMatchMode.IN;
    } else {
      return FilterMatchMode.STARTS_WITH;
    }
  }

  // Remark: Only For LazyLoad is true.
  onChangeTableFilters(event: TableLazyLoadEvent): void {
    // Remark: First and current page is essential For payload.
    this.tableConfig.first = event?.first || 0;
    this.rows = event?.rows || DEFAULT_ROW_PER_PAGE;
    const currentPage = this.tableConfig.first / this.rows + 1;

    // Remark: Create Payload section.
    const selectedColumnFilter = this.transformFilterValue(
      this.appliedFilters,
    ).filter((item) => !(item.operator === 'IN' && item.value === ''));
    const newPayload: ITableSearchPayload = {
      rowPerPage: this.rows,
      pageNumber: currentPage || 1,
      sortBy: event.sortField,
      sortType: this.getSortOrder(event.sortOrder, event.sortField as string),
      searchParams: { columns: selectedColumnFilter },
    };

    this.onChangeTableFiltersEmit.emit(newPayload);
  }

  getSortOrder(
    sortOrder: number | undefined | null,
    sortField: string | undefined,
  ): 'ASC' | 'DESC' {
    if (sortField === undefined) {
      return 'DESC';
    }
    return sortOrder === 1 ? 'ASC' : 'DESC';
  }

  transformFilterValue(
    input: Record<string, FilterMetadata | undefined>,
  ): IFilterColumn[] {
    const filters = Object.entries(input)
      .filter(
        ([_, filter]) => filter?.value !== null && filter?.value !== undefined,
      )
      .map(([key, filter]) => {
        // Check if the key ends with or contains '_date' (case-insensitive)
        const isDateKey = key.toLowerCase().endsWith('_date');

        if (isDateKey) {
          // Cast filter.value as string array for the date range logic
          const dateArray = filter?.value as string[];

          // Handle cases where dateArray might be empty or missing
          const startDate = dateArray?.[0];
          const endDate = dateArray?.[1] ?? startDate;

          const expected: string[] = [startDate, endDate];
          const formatDateValue = this.formatDate(expected);

          return {
            fieldName: key,
            operator: 'between',
            value: formatDateValue,
          };
        } else {
          return {
            fieldName: key,
            operator: this.getOperator(filter?.matchMode),
            value: String(filter?.value),
          };
        }
      });

    return filters;
  }

  formatDate = (dateInput: string | string[]): string | string[] => {
    const pad = (n: number) => n.toString().padStart(2, '0');
    const format = (dateString: string) => {
      const fullDate = new Date(dateString);

      const date = `${pad(fullDate.getDate())}`;
      const month = `${pad(fullDate.getMonth() + 1)}`;
      const year = `${fullDate.getFullYear()}`;

      return `${year}-${month}-${date}`;
    };

    if (Array.isArray(dateInput)) {
      const result: string[] = [];
      for (const element of dateInput) {
        result.push(format(element));
      }
      // For between use string instead of array string 'from date, to date' -> '2025-06-12,2025-06-21'
      return result.join(',');
    }

    return format(dateInput);
  };

  private getOperator(operatorString: string | undefined): string {
    let operator: string;
    switch (operatorString?.toLowerCase()) {
      // Remark: Can use FilterMatchMode from primeNG version 19 but this switch case base on OPERATOR that handle in client-gio.
      // Can change or add more case later.
      case 'startswith':
        operator = OPERATOR.STARTS_WITH;
        break;
      case 'contains':
        operator = OPERATOR.LIKE;
        break;
      case 'endswith':
        operator = OPERATOR.ENDS_WITH;
        break;
      case 'equals':
        operator = OPERATOR.EQUAL;
        break;
      case 'notequals':
        operator = OPERATOR.NOT_EQUAL;
        break;
      case 'in':
        operator = OPERATOR.IN;
        break;
      default:
        operator = OPERATOR.STARTS_WITH;
        break;
    }
    return operator;
  }
}
