import { CommonModule } from '@angular/common';
import {
  Component,
  EventEmitter,
  inject,
  Input,
  OnChanges,
  OnInit,
  Output,
  SimpleChanges,
} from '@angular/core';
import { SplitButtonModule } from 'primeng/splitbutton';
import { MenuItem } from 'primeng/api';

@Component({
  selector: 'pla-content-container',
  templateUrl: './pla-content-container.component.html',
  styleUrls: ['./pla-content-container.component.scss'],
  imports: [CommonModule, SplitButtonModule],
  standalone: true,
})
export class PlaContentContainerComponent implements OnInit, OnChanges {
  @Input() title = 'Title';
  @Input() menuList: {
    label_key: string;
    value: string;
  }[] = [];
  @Input() selectMenu: {
    label_key: string;
    value: string;
  } | null = null;

  @Output() selectMenuChange = new EventEmitter<{
    label_key: string;
    value: string;
  }>();

  splitButtonMenu: MenuItem[] = [];

  ngOnChanges(changes: SimpleChanges): void {
    if (changes?.['menuList']?.currentValue) {
      this.initialMenu();
    }
  }

  async ngOnInit() {
    this.initialMenu();

    if (this.selectMenu) {
      this.selectMenuChange.emit(this.selectMenu);
    } else {
      this.selectMenu = this.menuList[0];
      this.selectMenuChange.emit(this.menuList[0]);
    }
  }

  initialMenu(): void {
    this.splitButtonMenu = this.menuList.map((menu) => {
      return {
        label: menu.label_key,
        command: () => {
          this.onSelectMenu(menu);
        },
      };
    });
  }

  onSelectMenu(menu: { label_key: string; value: string }): void {
    this.selectMenuChange.emit(menu);
  }
}
