import { FilterMetadata } from 'primeng/api';
import { ICommonData, TagSeverity } from '../public-api';

export type AlignType = 'center' | 'left' | 'right';
export type ColumnType = 'text' | 'date' | 'decimal' | 'tag' | 'action';
export type FilterType = 'input-text' | 'multi-select' | 'date';

export interface IOperatorOptions {
  label: string;
  value: string;
}
export interface IAppliedFilters {
  [key: string]: FilterMetadata;
}
export interface ITablePaginator {
  isShowPagination: boolean;
  paginatorProperties: IPaginatorProperties;
}

export interface IPaginatorProperties {
  rowsPerPageOptions: number[];
  showCurrentPageReport: boolean;
  currentPageReportTemplate: string;
  paginatorDropdownAppendTo: 'body' | 'self';
}

export interface ITableLazyLoad {
  islazyLoad: boolean;
  totalRecord: number;
}

export interface ITableConfig {
  first: number;
  rows: number;
  tableLazyLoadConfig: ITableLazyLoad;
  tablePaginatorConfig: ITablePaginator;
}

// Remark: <T> is a generic type that will be used to emit data by action buttons or custom cell.
export interface ITableColumn<T> {
  minWidth?: string; // For row width.
  maxWidth?: string; // For row width.

  // Remark: Header
  field: string; // null for action column
  title: string;
  columnType: ColumnType;
  headerAlign?: AlignType;
  isDisableSort?: boolean; // For disabled sort action.
  // Remark: Filter
  isHidePlaceholder?: boolean;
  filterWidth?: string;
  isDisplayFilter?: boolean;
  filterType?: FilterType;
  options?: ICommonData[]; // For filter type dropown and custom dropdown.
  searchField?: string; // For filter type dropown and custom dropdown. Which field in table you want to search.
  searchFunction?: (query: IFilteredOptions) => void; // For filter type dropown and custom dropdown. Search options in speicific column.
  loading?: boolean;

  // Remark: Body
  textAlign?: AlignType;
  decimalDigit?: string;
  emptyValueText?: string;
  dateFormat?: string; // Using date pipe format from Common
  severity?: TagSeverity; // For tag column
  // Remark: Action Column
  action_Disable?: Record<string, string>;
  action_Buttons?: IActionButton<T>[];
  // Remark: Frozen Column
  frozenColumn?: boolean;
  alignFrozen?: AlignType;
}

export interface IFilteredOptions<T = string> {
  originalEvent: Event;
  filter: T;
}

export interface IActionButton<T> {
  label: string;
  icon?: string;
  svg?: string;
  onActionClick: (row: T) => void;
  separator?: boolean;
  items?: IActionButton<T>[];
  disabled?: boolean;
  permission?: string;
}

export enum FILTER_TYPE {
  INPUT_TEXT = 'INPUT_TEXT',
  DATE = 'DATE',
  SELECT = 'SELECT',
  MULTI_SELECT = 'MULTI_SELECT',
  CUSTOM_SELECT = 'CUSTOM_SELECT',
}

export interface IFilterColumn {
  fieldName: string;
  operator: string;
  value: string | string[];
}

export enum OPERATOR {
  EQUAL = 'EQUAL',
  NOT_EQUAL = 'NOT_EQUAL',
  GREATER_THAN = 'GREATER_THAN',
  GREATER_THAN_OR_EQUAL = 'GREATER_THAN_OR_EQUAL',
  LESS_THAN = 'LESS_THAN',
  LESS_THAN_OR_EQUAL = 'LESS_THAN_OR_EQUAL',
  LIKE = 'LIKE',
  STARTS_WITH = 'STARTS_WITH',
  ENDS_WITH = 'ENDS_WITH',
  IN = 'IN',
  IS_NULL = 'IS_NULL',
  IS_NOT_NULL = 'IS_NOT_NULL',
}

export interface ITableSearchPayload {
  rowPerPage: number;
  pageNumber: number;
  sortBy: string | string[] | null | undefined;
  sortType: string;
  searchParams: { columns: IFilterColumn[] };
}
