import { Injectable } from '@angular/core';
import { MenuService } from './menu.service';
import { Router } from '@angular/router';
import { inject } from '@angular/core';
import { IMenu } from '../models/user-profile.interface';

@Injectable({ providedIn: 'root' })
export class PermissionService {
  private readonly menuService = inject(MenuService);
  private readonly router = inject(Router);

  async hasPermission(permission: string, storage: string): Promise<boolean> {
    const currentUrl = this.router.url;
    const targetMenu = await this.menuService.getGroupMenu(currentUrl, storage);
    const grantedPermission = new Set(
      (targetMenu?.targetMenu?.permission || '[]')
        .replace(/^\[|\]$/g, '')
        .split(',')
        .map((item: string) => item.trim()),
    );
    return grantedPermission.has(permission);
  }

  async hasMenuUAM(url: string, storage: string): Promise<IMenu | null> {
    const targetMenu = await this.menuService.getGroupMenu(url, storage);
    return targetMenu;
  }
}
