import { Component, EventEmitter, Input, Output } from '@angular/core';
import { DialogModule } from 'primeng/dialog';
import { ButtonModule } from 'primeng/button';
import { AngularSvgIconModule } from 'angular-svg-icon';

@Component({
  selector: 'pla-confirm-modal',
  templateUrl: './pla-confirm-modal.component.html',
  styleUrls: ['./pla-confirm-modal.component.scss'],
  imports: [DialogModule, ButtonModule, AngularSvgIconModule],
  standalone: true,
})
export class PlaConfirmModalComponent {
  @Input() isVisible = false;
  @Input() image = 'assets/svg/icon-bell.svg';
  @Input() title = 'Title';
  @Input() description = 'description';
  @Input() saveText = 'Save';
  @Input() cancelText = 'Cancel';

  @Output() isVisibleChange = new EventEmitter<boolean>();
  @Output() isCancel = new EventEmitter();
  @Output() isSubmit = new EventEmitter();

  onClickCancel(isReject: boolean): void {
    this.isVisibleChange.emit(false);

    if (isReject) {
      this.isCancel.emit();
    }
  }

  onClickSubmit(): void {
    this.isVisibleChange.emit(false);
    this.isSubmit.emit();
  }
}
